import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

export const SystemBoot: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const [stage, setStage] = useState(0);
  const messages = [
    "INITIALIZING NEURAL LINK...",
    "LOADING AYANOKOJI PROTOCOLS...",
    "SYNCHRONIZING JINWOO ATTRIBUTES...",
    "CALIBRATING SYSTEM OVERLAY...",
    "ACCESS GRANTED."
  ];

  useEffect(() => {
    if (stage < messages.length) {
      const timer = setTimeout(() => setStage(prev => prev + 1), 800);
      return () => clearTimeout(timer);
    } else {
      const timer = setTimeout(onComplete, 1000);
      return () => clearTimeout(timer);
    }
  }, [stage, onComplete]);

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-6 bg-grid">
      <div className="scanline" />
      
      <motion.div
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        className="relative w-64 h-64 mb-12 flex items-center justify-center"
      >
        {/* Animated Rings */}
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
          className="absolute inset-0 border-2 border-primary/20 rounded-full border-t-primary"
        />
        <motion.div
          animate={{ rotate: -360 }}
          transition={{ duration: 15, repeat: Infinity, ease: "linear" }}
          className="absolute inset-4 border-2 border-secondary/20 rounded-full border-b-secondary"
        />
        
        <div className="system-terminal text-primary text-4xl font-black neon-glow-blue">
          H.S.
        </div>
      </motion.div>

      <div className="w-full max-w-xs space-y-4">
        <AnimatePresence mode="wait">
          <motion.div
            key={stage}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            className="system-terminal text-center text-xs tracking-[0.3em] text-primary/80"
          >
            {messages[stage] || "READY."}
          </motion.div>
        </AnimatePresence>

        <div className="h-1 bg-white/5 rounded-full overflow-hidden border border-white/5">
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${(stage / messages.length) * 100}%` }}
            className="h-full bg-gradient-to-r from-primary to-secondary shadow-[0_0_10px_rgba(0,242,255,0.5)]"
          />
        </div>
      </div>
    </div>
  );
};
