// Dashboard Page - System Home
import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { useAppStore } from '@/store';
import { db } from '@/db';
import { ALL_TASKS, QUOTES } from '@/constants';
import type { DayMode, DailyTask } from '@/types';
import {
  Flame, 
  Target, 
  Zap,
} from 'lucide-react';
import { calculateDailyCompletion } from '@/utils/scoring';

interface DashboardTask extends DailyTask {
  completed: boolean;
}

export function Dashboard() {
  const { profile, xpData, streakData, currentWeek, attributes } = useAppStore();
  const [dailyCompletion, setDailyCompletion] = useState(0);
  const [, setDayMode] = useState<DayMode>('green');
  const [quote, setQuote] = useState(QUOTES[0]);
  const [todayTasks, setTodayTasks] = useState<DashboardTask[]>([]);

  useEffect(() => {
    const loadData = async () => {
      const now = new Date();
      const completion = await calculateDailyCompletion(now, profile?.currentStage || 1);
      setDailyCompletion(completion);

      const mode = await db.getDayModeForDate(now);
      const currentMode = mode?.mode || 'green';
      setDayMode(currentMode);

      const weekday = now.getDay();
      const stage = profile?.currentStage || 1;
      
      const startOfDay = new Date();
      startOfDay.setHours(0, 0, 0, 0);
      const endOfDay = new Date();
      endOfDay.setHours(23, 59, 59, 999);
      
      const completions = await db.getCompletionsForDateRange(startOfDay, endOfDay);
      
      const tasks: DashboardTask[] = ALL_TASKS
        .filter((t: DailyTask) => t.stage === stage && t.frequency === 'daily' && t.dayModeAvailability.includes(currentMode))
        .filter((t: DailyTask) => {
           if (t.id === 'training') return [0, 1, 2, 3, 4].includes(weekday);
           return true;
        })
        .map((t: DailyTask) => ({
          ...t,
          completed: completions.some(c => c.taskId === t.id && c.completed)
        }))
        .sort((a, b) => a.order - b.order);
        
      setTodayTasks(tasks);

      if (profile) {
        const category = profile.hardcoreMode ? 'solo-leveling' : (Math.random() > 0.5 ? 'cote' : 'solo-leveling');
        const filteredQuotes = QUOTES.filter(q => q.category === category);
        setQuote(filteredQuotes[Math.floor(Math.random() * filteredQuotes.length)] || QUOTES[0]);
      }
    };

    if (profile) {
      void loadData();
    }
  }, [profile, currentWeek, attributes]);

  return (
    <div className="min-h-screen p-6 pb-24 space-y-8 max-w-lg mx-auto">
      {/* Cinematic Header */}
      <motion.header
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        className="relative flex justify-between items-end pb-4 border-b border-white/5"
      >
        <div className="space-y-1">
          <div className="system-terminal text-[10px] text-primary/60 tracking-[0.3em]">TACTICAL STATUS</div>
          <h1 className="system-terminal text-2xl font-black text-white neon-glow-blue">
            COMMANDER
          </h1>
        </div>
        <div className="text-right">
          <div className="system-terminal text-[10px] text-muted-foreground">CURRENT WEEK</div>
          <div className="system-terminal text-2xl font-bold text-primary">{currentWeek}</div>
        </div>
        {/* Animated Corner Decor */}
        <div className="absolute bottom-0 left-0 w-8 h-[2px] bg-primary shadow-[0_0_10px_rgba(0,242,255,0.5)]" />
      </motion.header>

      {/* Dynamic Aura XP Card */}
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="system-window p-6 bg-gradient-to-br from-primary/10 via-transparent to-secondary/5 group"
      >
        <div className="flex justify-between items-center mb-8">
          <div className="space-y-1">
            <div className="system-terminal text-[10px] text-primary/80">SYSTEM LEVEL</div>
            <div className="system-terminal text-5xl font-black text-white group-hover:neon-glow-blue transition-all">
              {xpData?.level || 1}
            </div>
          </div>
          <div className="relative">
            <div className="w-16 h-16 rounded-sm border border-primary/20 flex items-center justify-center bg-black/40">
              <Zap className="w-8 h-8 text-primary aura-pulse" />
            </div>
            {/* Pulsing Aura Rings */}
            <div className="absolute inset-0 border border-primary/20 rounded-sm animate-ping opacity-20" />
          </div>
        </div>

        <div className="space-y-3">
          <div className="flex justify-between system-terminal text-[9px] text-muted-foreground">
            <span className="text-primary/80">EXPERIENCE PROTOCOL</span>
            <span className="font-mono">{xpData?.currentXP || 0} / {xpData?.xpToNextLevel || 100}</span>
          </div>
          <div className="h-3 bg-white/5 border border-white/10 rounded-full p-[2px] overflow-hidden">
            <motion.div
              initial={{ width: 0 }}
              animate={{ width: `${((xpData?.currentXP || 0) / (xpData?.xpToNextLevel || 100)) * 100}%` }}
              className="h-full bg-gradient-to-r from-primary via-secondary to-primary bg-[length:200%_100%] animate-[gradient_4s_linear_infinite] rounded-full shadow-[0_0_15px_rgba(var(--primary-rgb),0.4)]"
            />
          </div>
        </div>
      </motion.div>

      {/* Main Stats Grid */}
      <div className="grid grid-cols-2 gap-4">
        <StatusBox 
          icon={<Flame className="w-4 h-4 text-orange-500" />}
          label="STREAK"
          value={streakData?.dailyStreak || 0}
          unit="DAYS"
          delay={0.1}
        />
        <StatusBox 
          icon={<Target className="w-4 h-4 text-accent" />}
          label="COMPLIANCE"
          value={dailyCompletion}
          unit="%"
          delay={0.2}
        />
      </div>

      {/* Today's Objectives */}
      <motion.section
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.3 }}
        className="space-y-4"
      >
        <div className="flex justify-between items-center px-1">
          <div className="system-terminal text-[10px] text-muted-foreground tracking-widest">SYSTEM OBJECTIVES</div>
          <div className="system-terminal text-[10px] text-primary">{todayTasks.filter(t => t.completed).length}/{todayTasks.length}</div>
        </div>
        
        <div className="space-y-3">
          {todayTasks.map((task: DashboardTask, index: number) => (
            <motion.div
              key={task.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.4 + index * 0.1 }}
              className={`system-window p-4 flex items-center gap-4 group cursor-pointer hover:bg-white/5 transition-all ${
                task.completed ? 'border-primary/40 bg-primary/5' : 'border-white/5'
              }`}
            >
              <div className={`w-5 h-5 rounded-sm border transition-all flex items-center justify-center ${
                task.completed ? 'bg-primary border-primary' : 'border-white/20 group-hover:border-primary/40'
              }`}>
                {task.completed && <Check className="w-3 h-3 text-black font-bold" />}
              </div>
              <div className="flex-1">
                <div className={`text-sm font-medium tracking-tight ${task.completed ? 'text-primary' : 'text-white/80'}`}>
                  {task.name.toUpperCase()}
                </div>
                <div className="system-terminal text-[8px] text-muted-foreground mt-1 opacity-60">
                  PROTOCOL: {task.category.toUpperCase()}
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </motion.section>

      {/* Advisory Quote */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.8 }}
        className="system-window p-6 border-l-4 border-l-primary bg-primary/5"
      >
        <p className="text-sm text-white/90 leading-relaxed font-mono italic">
          &ldquo;{quote.text}&rdquo;
        </p>
        <div className="system-terminal text-[9px] text-primary/60 mt-4 text-right">
          SOURCE: {quote.author.toUpperCase()}
        </div>
      </motion.div>
    </div>
  );
}

const StatusBox = ({ icon, label, value, unit, delay }: any) => (
  <motion.div
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0 }}
    transition={{ delay }}
    className="system-window p-4 space-y-3 group"
  >
    <div className="flex items-center gap-2">
      {icon}
      <span className="system-terminal text-[9px] text-muted-foreground tracking-widest">{label}</span>
    </div>
    <div className="flex items-baseline gap-1">
      <span className="system-terminal text-2xl font-black group-hover:text-primary transition-colors">{value}</span>
      <span className="system-terminal text-[10px] text-muted-foreground">{unit}</span>
    </div>
  </motion.div>
);

const Check = ({ className }: { className?: string }) => (
  <svg className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" />
  </svg>
);
